const cfg = $('Set API and Share Link Parameters').first().json;
const rows = $input.all();
const output = [];

for (const row of rows) {
  const root = row.json || {};
  const data = root?.data || {};

  const redirectUrl = data?.redirect_url || data?.redirectUrl || data?.resolved_url || data?.url || data?.target_url || data?.jump_url || data?.origin_url || '';
  const originalUrl = cfg?.shareUrl || data?.original_url || data?.source_url || '';

  let normalizedUrl = '';
  let noteId = data?.note_id || data?.noteId || data?.id || '';
  let userId = data?.user_id || data?.userId || '';
  let xsecToken = data?.xsec_token || data?.xsecToken || '';
  let linkType = data?.type || data?.link_type || data?.object_type || '';
  let shareChannel = '';
  let shareSource = '';
  let appPlatform = '';
  let appVersion = '';
  let title = data?.title || '';

  if (redirectUrl) {
    try {
      const parsed = new URL(redirectUrl);
      normalizedUrl = `${parsed.origin}${parsed.pathname}`;

      const pathParts = parsed.pathname.split('/').filter(Boolean);
      const itemIndex = pathParts.indexOf('item');
      if (!noteId && itemIndex >= 0 && pathParts[itemIndex + 1]) {
        noteId = pathParts[itemIndex + 1];
      }

      if (!xsecToken) {
        xsecToken = parsed.searchParams.get('xsec_token') || '';
      }
      if (!linkType) {
        linkType = parsed.searchParams.get('type') || '';
      }
      shareChannel = parsed.searchParams.get('share_channel') || '';
      shareSource = parsed.searchParams.get('xsec_source') || '';
      appPlatform = parsed.searchParams.get('app_platform') || '';
      appVersion = parsed.searchParams.get('app_version') || '';
      userId = userId || parsed.searchParams.get('user_id') || '';
    } catch (error) {
      normalizedUrl = redirectUrl;
    }
  }

  output.push({
    json: {
      baseUrl: cfg?.baseUrl || '',
      originalShareUrl: originalUrl,
      code: root?.code ?? null,
      message: root?.message ?? null,
      recordTime: root?.recordTime || '',
      redirectUrl,
      normalizedUrl,
      noteId,
      userId,
      xsecToken,
      linkType,
      title,
      shareChannel,
      shareSource,
      appPlatform,
      appVersion,
      rawData: data,
      raw: root
    }
  });
}

return output;
